     8	{
     9	    public class BoundingBox
    10	    {
    11	        public Point TopLeft { get; set; }
    12	        public Point TopRight { get; set; }
    13	        public Point BottomRight { get; set; }
    14	        public Point BottomLeft { get; set; }
    15	
    16	        public BoundingBox(Point topLeft, Point topRight, Point bottomRight, Point bottomLeft)
    17	        {
    18	            TopLeft = topLeft;
    19	            TopRight = topRight;
    20	            BottomRight = bottomRight;
    21	            BottomLeft = bottomLeft;
    22	        }
    23	
    24	        public double Width => Math.Max(
    25	            Math.Abs(TopRight.X - TopLeft.X),
    26	            Math.Abs(BottomRight.X - BottomLeft.X)
    27	        );
    28	
    29	        public double Height => Math.Max(
    30	            Math.Abs(BottomLeft.Y - TopLeft.Y),
    31	            Math.Abs(BottomRight.Y - TopRight.Y)
    32	        );
    33	
    34	        public Point Center => new Point(
    35	            (TopLeft.X + TopRight.X + BottomRight.X + BottomLeft.X) / 4,
    36	            (TopLeft.Y + TopRight.Y + BottomRight.Y + BottomLeft.Y) / 4
    37	        );
    38	    }
