    52	    public class TextDetectionResult
    53	    {
    54	        public string Text { get; set; } = string.Empty;
    55	        public double Confidence { get; set; }
    56	        public BoundingBox BoundingBox { get; set; } = new BoundingBox(
    57	            topLeft: new Point(0, 0),
    58	            topRight: new Point(0, 0),
    59	            bottomRight: new Point(0, 0),
    60	            bottomLeft: new Point(0, 0)
    61	        );
    62	    }
