    65	    public TextDetectionResult Parse(string input)
    66	    {
    67	        // Extract text using regex
    68	        var textMatch = Regex.Match(input, @"\([""'](.*)[""'],");
    69	        var text = textMatch.Groups[1].Value;
    70	
    71	        // Extract confidence using regex
    72	        input = input.Replace(" ", string.Empty);
    73	        var confidenceMatch = Regex.Match(input, @"(\d+\.\d+)\)\]$");
    74	        var confidence = double.Parse(confidenceMatch.Groups[1].Value, CultureInfo.InvariantCulture);
    75	
    76	        // Extract coordinates using regex
    77	        var coordMatches = Regex.Matches(input, @"\[(\d+\.\d+),(\d+\.\d+)\]");
    78	
    79	        var points = new Point[4];
    80	        for (var i = 0; i < 4; i++)
    81	        {
    82	            var match = coordMatches[i];
    83	            points[i] = new Point(
    84	                double.Parse(match.Groups[1].Value, CultureInfo.InvariantCulture),
    85	                double.Parse(match.Groups[2].Value, CultureInfo.InvariantCulture)
    86	            );
    87	        }
    88	
    89	        var boundingBox = new BoundingBox(
    90	            topLeft: points[0],
    91	            topRight: points[1],
    92	            bottomRight: points[2],
    93	            bottomLeft: points[3]
    94	        );
    95	
    96	        return new TextDetectionResult
    97	        {
    98	            Text = text,
    99	            Confidence = confidence,
   100	            BoundingBox = boundingBox
   101	        };
   102	    }
   103	}
