   171	        }
   172	
   173	        // Get all pixels at once
   174	        var colors = workingBitmap.Pixels;
   175	        var blackOpaque = new SKColor(0, 0, 0, 255);
   176	
   177	        for (int i = 0; i < colors.Length; i++)
