   257	    private List<List<PaddleOcrResultParser.TextDetectionResult>> MakeLines(
   258	        List<PaddleOcrResultParser.TextDetectionResult> input)
   259	    {
   260	        var result = new List<List<PaddleOcrResultParser.TextDetectionResult>>();
   261	        var heightAverage = input.Average(p => p.BoundingBox.Height);
   262	        var sorted = input.OrderBy(p => p.BoundingBox.Center.Y);
   263	        var line = new List<PaddleOcrResultParser.TextDetectionResult>();
   264	        PaddleOcrResultParser.TextDetectionResult? last = null;
   265	        foreach (var element in sorted)
   266	        {
   267	            if (last == null)
   268	            {
   269	                line.Add(element);
   270	            }
   271	            else
   272	            {
   273	                if (element.BoundingBox.Center.Y > last.BoundingBox.TopLeft.Y + heightAverage)
   274	                {
   275	                    result.Add(line.OrderBy(p => p.BoundingBox.TopLeft.X).ToList());
   276	                    line = new List<PaddleOcrResultParser.TextDetectionResult>();
   277	                }
   278	
   279	                line.Add(element);
   280	            }
   281	
   282	            last = element;
   283	        }
   284	
   285	        if (line.Count > 0)
   286	        {
   287	            result.Add(line.OrderBy(p => p.BoundingBox.TopLeft.X).ToList());
   288	        }
   289	
   290	        return result;
   291	    }
