using Nikse.SubtitleEdit.Features.Ocr;

namespace UITests.Features.Ocr.Engines;

public class PaddleOcrResultParserTests
{
    [Fact]
    public void Parse_NormalText_ReturnsCorrectText()
    {
        var parser = new PaddleOcrResultParser();
        var input = "[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], ('My mommy always said', 0.9907816052436829)]";
        var result = parser.Parse(input);
        Assert.Equal("My mommy always said", result.Text);
    }

    [Fact]
    public void Parse_TextWithDoubleQuote_ParsesCorrectly()
    {
        var parser = new PaddleOcrResultParser();
        // Python represents a string with both " and ' using single quotes and escaping single quotes
        var input = "[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], ('\" It\\'s raining...', 0.9907816052436829)]";
        var result = parser.Parse(input);
        Assert.Equal("\" It's raining...", result.Text);
    }

    [Fact]
    public void Parse_TextWithOnlyDoubleQuotes_ReturnsCorrectText()
    {
        var parser = new PaddleOcrResultParser();
        var input = "[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], ('He said \"hello\"', 0.9907816052436829)]";
        var result = parser.Parse(input);
        Assert.Equal("He said \"hello\"", result.Text);
    }

    [Fact]
    public void Parse_TextWithOnlySingleQuote_ReturnsCorrectText()
    {
        var parser = new PaddleOcrResultParser();
        var input = "[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], (\"It's raining\", 0.9907816052436829)]";
        var result = parser.Parse(input);
        Assert.Equal("It's raining", result.Text);
    }

    [Fact]
    public void Parse_TextWithEscapedBackslash_ReturnsCorrectText()
    {
        var parser = new PaddleOcrResultParser();
        var input = "[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], ('path\\\\to\\\\file', 0.99)]";
        var result = parser.Parse(input);
        Assert.Equal("path\\to\\file", result.Text);
    }
}

