    25	            Math.Abs(TopRight.X - TopLeft.X),
    26	            Math.Abs(BottomRight.X - BottomLeft.X)
    27	        );
    28	
    29	        public double Height => Math.Max(
    30	            Math.Abs(BottomLeft.Y - TopLeft.Y),
    31	            Math.Abs(BottomRight.Y - TopRight.Y)
    32	        );
    33	
    34	        public Point Center => new Point(
    35	            (TopLeft.X + TopRight.X + BottomRight.X + BottomLeft.X) / 4,
    36	            (TopLeft.Y + TopRight.Y + BottomRight.Y + BottomLeft.Y) / 4
    37	        );
    38	    }
