    64	
    65	    public TextDetectionResult Parse(string input)
    66	    {
    67	        // Extract text using regex - captures delimiter (single or double quote) and uses backreference
    68	        // to match the same closing delimiter. Handles Python str() representation where:
    69	        // - single-quoted strings escape ' as \' and \ as \\
    70	        // - double-quoted strings escape " as \" and \ as \\
    71	        var textMatch = Regex.Match(input, @"\(([""'])(.*)\1,");
    72	        var text = textMatch.Groups[2].Value;
    73	        var delimiter = textMatch.Groups[1].Value;
    74	
    75	        // Unescape Python string escape sequences
    76	        text = text.Replace("\\\\", "\\"); // Must be first: \\ -> \
    77	        if (delimiter == "'")
    78	        {
    79	            text = text.Replace("\\'", "'");
    80	        }
    81	        else
    82	        {
    83	            text = text.Replace("\\\"", "\"");
    84	        }
    85	
    86	        // Extract confidence using regex
    87	        input = input.Replace(" ", string.Empty);
    88	        var confidenceMatch = Regex.Match(input, @"(\d+\.\d+)\)\]$");
    89	        var confidence = double.Parse(confidenceMatch.Groups[1].Value, CultureInfo.InvariantCulture);
    90	
    91	        // Extract coordinates using regex
    92	        var coordMatches = Regex.Matches(input, @"\[(\d+\.\d+),(\d+\.\d+)\]");
    93	
    94	        var points = new Point[4];
    95	        for (var i = 0; i < 4; i++)
    96	        {
    97	            var match = coordMatches[i];
    98	            points[i] = new Point(
    99	                double.Parse(match.Groups[1].Value, CultureInfo.InvariantCulture),
   100	                double.Parse(match.Groups[2].Value, CultureInfo.InvariantCulture)
   101	            );
   102	        }
   103	
   104	        var boundingBox = new BoundingBox(
   105	            topLeft: points[0],
   106	            topRight: points[1],
   107	            bottomRight: points[2],
   108	            bottomLeft: points[3]
   109	        );
   110	
   111	        return new TextDetectionResult
   112	        {
   113	            Text = text,
   114	            Confidence = confidence,
   115	            BoundingBox = boundingBox
   116	        };
   117	    }
   118	}
